export class Governance_view {
  constructor() {}

  render_anchor_tags = (elements) => {
    const ul = document.getElementById("governance-main-article-ul1");

    elements.forEach((element) => {
      const li = document.createElement("li");
      const a = document.createElement("a");
      const p = document.createElement("p");

      li.classList.add("governance-main-article-ul-li");
      a.classList.add("governance-main-article-ul-li-a");
      a.setAttribute("target", "_blank");
      if (process.env.NODE_ENV === "production") {
        a.setAttribute("href", element.production_url);
      } else {
        a.setAttribute("href", element.development_url);
      }
      p.classList.add("governance-main-article-ul-li-a-p");

      p.textContent = element.name;

      a.appendChild(p);
      li.appendChild(a);
      ul.appendChild(li);
    });
  };
}
