import { Governance_model } from "../model/model.js";
import { Governance_view } from "../view/view.js";

export class Governance_controller {
  constructor() {
    console.log("Governance_controller working");

    this.model = new Governance_model();
    this.view = new Governance_view();

    this.model
      .fetch_anchor_tags()
      .then((res) => {
        if (res.elements) {
          this.view.render_anchor_tags(res.elements);
        }
      })
      .catch((err) => {
        console.log(err);
      });
  }
}
